import numpy as np
from scipy.optimize import minimize

def find_all_minima(f, bounds, num_starts=20):
    minima = []
    for _ in range(num_starts):
        x0 = [np.random.uniform(b[0], b[1]) for b in bounds]
        res = minimize(f, x0, method='L-BFGS-B', bounds=bounds)
        if res.success:
            is_new = True
            for m in minima:
                if np.allclose(res.x, m['x'], atol=0.1):
                    is_new = False
                    break
            if is_new:
                minima.append({'x': res.x, 'f': res.fun})
    return sorted(minima, key=lambda m: m['f'])

def rastrigin(x):
    return 10*len(x) + sum(xi**2 - 10*np.cos(2*np.pi*xi) for xi in x)

minima = find_all_minima(rastrigin, [(-5, 5), (-5, 5)])
print(f"Found {len(minima)} minima")
for m in minima[:3]:
    print(f"  x={m['x']}, f={m['f']:.4f}")

import numpy as np

def landscape_slice(f, center, resolution=50, width=np.pi):
    x = np.linspace(center[0]-width, center[0]+width, resolution)
    y = np.linspace(center[1]-width, center[1]+width, resolution)
    X, Y = np.meshgrid(x, y)
    Z = np.zeros_like(X)
    for i in range(resolution):
        for j in range(resolution):
            Z[i,j] = f([X[i,j], Y[i,j]])
    return {'X': X, 'Y': Y, 'Z': Z, 'min': Z.min(), 'max': Z.max()}

def f(x): return np.sin(x[0]) * np.cos(x[1])
data = landscape_slice(f, [0, 0])
print(f"Landscape shape: {data['Z'].shape}")
print(f"Value range: [{data['min']:.3f}, {data['max']:.3f}]")
